import { enet_peer_disconnect, enet_peer_reset, enet_peer_send, } from "./native/index.js";
const disconnect = (peer, data) => {
    enet_peer_disconnect(peer.native, data);
};
const reset = (peer) => {
    enet_peer_reset(peer.native);
};
const send = (peer, channelID, packet) => enet_peer_send(peer.native, channelID, packet.native);
export { disconnect, reset, send };
